// 早期成就使用的语义名称与图标库名称并不完全一致；统一映射可避免回退成同一颗星。
const SVG_ALIASES = {
    awakening: 'light', bus: 'car', calm: 'moon', camping: 'nature', charity: 'gift',
    daydream: 'cloud', discipline: 'target', finance: 'money', firstlove: 'love',
    gamer: 'game', genius: 'star', healer: 'health', house: 'home', internet: 'tech',
    license: 'key', lonely: 'moon', longterm: 'clock', marathon: 'sport', passion: 'fire',
    reading: 'book', romantic: 'love', sidehustle: 'briefcase', smile: 'sun',
    startup: 'rocket', takeout: 'food', timemanage: 'clock'
};

function generateSVG(iconName, rarity = 'silver') {
    const colors = SVG_COLORS[rarity] || SVG_COLORS['silver'];
    const [c1, c2, c3] = colors;
    const resolvedIcon = SVG_ALIASES[iconName] || iconName;
    const pattern = SVG_PATTERNS[resolvedIcon] || SVG_PATTERNS['star'];
    const svgContent = pattern.replace(/{c1}/g, c1).replace(/{c2}/g, c2).replace(/{c3}/g, c3);
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 128 128" width="64" height="64"><rect width="128" height="128" fill="transparent"/>${svgContent}</svg>`;
}
